            <span className={`${letterClass} _14`}>'m</span> */}
                <img src={SquarePortrait} alt="portrait" className="portrait"/>
                <br/>
                <AnimatedLetters
              letterClass={letterClass}
              strArray={nameArray}
              idx={15}
            />
            <br />
            <AnimatedLetters
              letterClass={letterClass}
              strArray={jobArray}
              idx={22}
            />
         </h1>
         <h2>Fullstack Software Engineer</h2>
          <Link to="/contact" className="flat-button">
            CONTACT ME
          </Link>
        </div>

    </div>
);

}

export default Home
